use prompty::model::SessionFileRef;
use prompty::model::context::{LoadContext, SaveContext};

#[test]
fn test_session_file_ref_load_json() {
    let json = r####"
{
  "sessionId": "sess_abc123",
  "path": "src/index.ts",
  "toolName": "view",
  "turnIndex": 2,
  "firstSeenAt": "2026-06-09T20:00:00Z"
}
"####;
    let ctx = LoadContext::default();
    let result = SessionFileRef::from_json(json, &ctx);
    assert!(result.is_ok(), "Failed to load from JSON: {:?}", result.err());
    let instance = result.unwrap();
    assert!(instance.session_id.is_some(), "Expected session_id to be Some");
    assert_eq!(instance.session_id.as_ref().unwrap(), &"sess_abc123");
    assert_eq!(instance.path, "src/index.ts");
    assert!(instance.tool_name.is_some(), "Expected tool_name to be Some");
    assert_eq!(instance.tool_name.as_ref().unwrap(), &"view");
    assert!(instance.turn_index.is_some(), "Expected turn_index to be Some");
    assert_eq!(instance.turn_index.as_ref().unwrap(), &2);
    assert!(instance.first_seen_at.is_some(), "Expected first_seen_at to be Some");
    assert_eq!(instance.first_seen_at.as_ref().unwrap(), &"2026-06-09T20:00:00Z");
}

